import{_ as t,o as i,c as s,a2 as a}from"./chunks/framework.jWxB9oXr.js";const c=JSON.parse('{"title":"Link","description":"","frontmatter":{"head":[["meta",{"property":"og:title","content":"Link"}],["meta",{"property":"og:description","content":"Link component in Silvery — usage, props, examples, and best practices for terminal UIs."}],["meta",{"property":"og:url","content":"https://silvery.dev/components/Link.html"}],["link",{"rel":"canonical","href":"https://silvery.dev/components/Link.html"}],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"BreadcrumbList\\",\\"itemListElement\\":[{\\"@type\\":\\"ListItem\\",\\"position\\":1,\\"name\\":\\"Home\\",\\"item\\":\\"https://silvery.dev/\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":2,\\"name\\":\\"Components\\",\\"item\\":\\"https://silvery.dev/components\\"},{\\"@type\\":\\"ListItem\\",\\"position\\":3,\\"name\\":\\"Link\\",\\"item\\":\\"https://silvery.dev/components/Link\\"}]}"],["script",{"type":"application/ld+json"},"{\\"@context\\":\\"https://schema.org\\",\\"@type\\":\\"TechArticle\\",\\"headline\\":\\"Link\\",\\"description\\":\\"Link component in Silvery — usage, props, examples, and best practices for terminal UIs.\\",\\"url\\":\\"https://silvery.dev/components/Link.html\\",\\"dateModified\\":\\"2026-04-02T02:17:28.000Z\\",\\"datePublished\\":\\"2026-04-02T02:17:28.000Z\\",\\"image\\":\\"https://silvery.dev/og-image.png\\",\\"author\\":{\\"@type\\":\\"Person\\",\\"name\\":\\"Bjørn Stabell\\",\\"url\\":\\"https://beorn.codes\\",\\"sameAs\\":[\\"https://github.com/beorn\\"]}}"]]},"headers":[],"relativePath":"components/Link.md","filePath":"components/Link.md","lastUpdated":1775096248000}'),n={name:"components/Link.md"};function o(l,e,r,p,h,d){return i(),s("div",null,[...e[0]||(e[0]=[a(`<div style="display:none;" hidden="true" aria-hidden="true">Are you an LLM? You can read better optimized documentation at /components/<a href="/components/Link" class="hover-link" data-tooltip="Clickable OSC 8 hyperlink component — opens URLs in the user&#39;s browser">Link</a>.md for this page in Markdown format</div><h1 id="link" tabindex="-1">Link <a class="header-anchor" href="#link" aria-label="Permalink to &quot;Link&quot;">​</a></h1><p>Renders clickable hyperlinks using the <a href="/reference/terminal-protocols" class="hover-link" data-tooltip="Hyperlink escape sequence — makes text clickable in supporting terminals.">OSC 8</a> terminal escape sequence. <a href="/api/text" class="hover-link" data-tooltip="Styled text component with color, bold, italic, underline, and wrapping">Text</a> inside <code>&lt;Link&gt;</code> is wrapped in <a href="/reference/terminal-protocols" class="hover-link" data-tooltip="Hyperlink escape sequence — makes text clickable in supporting terminals.">OSC 8</a> sequences, making it clickable in supporting terminals (<a href="https://iterm2.com/" class="hover-link" data-tooltip="macOS terminal emulator with rich feature set — Sixel, imgcat, tmux integration, shell integration." target="_blank" rel="noopener">iTerm2</a>, Ghostty, Kitty, etc.).</p><h2 id="import" tabindex="-1">Import <a class="header-anchor" href="#import" aria-label="Permalink to &quot;Import&quot;">​</a></h2><div class="language-tsx vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">tsx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">import</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> { Link } </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">from</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;silvery&quot;</span></span></code></pre></div><h2 id="props" tabindex="-1">Props <a class="header-anchor" href="#props" aria-label="Permalink to &quot;Props&quot;">​</a></h2><p><code>LinkProps</code> extends <code>TextProps</code> (excluding <code>children</code>).</p><table tabindex="0"><thead><tr><th>Prop</th><th>Type</th><th>Default</th><th>Description</th></tr></thead><tbody><tr><td><code>href</code></td><td><code>string</code></td><td><strong>required</strong></td><td>URL to link to (http/https for external, custom schemes for internal)</td></tr><tr><td><code>children</code></td><td><code>ReactNode</code></td><td>--</td><td><a href="/components/Link" class="hover-link" data-tooltip="Clickable OSC 8 hyperlink component — opens URLs in the user&#39;s browser">Link</a> text content</td></tr><tr><td><code>variant</code></td><td><code>&quot;arm-on-cmd-hover&quot; | &quot;arm-on-hover&quot;</code></td><td><code>&quot;arm-on-cmd-hover&quot;</code></td><td>How the link arms for clicking</td></tr><tr><td><code>color</code></td><td><code>string</code></td><td><code>&quot;$link&quot;</code></td><td><a href="/components/Link" class="hover-link" data-tooltip="Clickable OSC 8 hyperlink component — opens URLs in the user&#39;s browser">Link</a> text color</td></tr></tbody></table><p>All <code>TextProps</code> style props (bold, italic, etc.) are also accepted.</p><h2 id="usage" tabindex="-1">Usage <a class="header-anchor" href="#usage" aria-label="Permalink to &quot;Usage&quot;">​</a></h2><div class="language-tsx vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">tsx</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Link</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> href</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://example.com&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;Visit Example&lt;/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Link</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Always clickable on hover (no modifier needed)</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Link</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> href</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;https://example.com&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> variant</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;arm-on-hover&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;Always Clickable&lt;/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Link</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">// Internal link with custom handler</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Link</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> href</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;app://node/abc123&quot;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> onClick</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{(</span><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">e</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">) </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=&gt;</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> navigate</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(e)}&gt;Internal Link&lt;/</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">Link</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><h2 id="behavior" tabindex="-1">Behavior <a class="header-anchor" href="#behavior" aria-label="Permalink to &quot;Behavior&quot;">​</a></h2><ul><li><strong><code>arm-on-cmd-hover</code></strong> (default): <a href="/components/Link" class="hover-link" data-tooltip="Clickable OSC 8 hyperlink component — opens URLs in the user&#39;s browser">Link</a> underlines and becomes clickable when hovered while holding Cmd/Super.</li><li><strong><code>arm-on-hover</code></strong>: <a href="/components/Link" class="hover-link" data-tooltip="Clickable OSC 8 hyperlink component — opens URLs in the user&#39;s browser">Link</a> underlines and becomes clickable on plain hover (no modifier needed).</li><li>On click (when armed), emits a <code>&quot;link:open&quot;</code> event via RuntimeContext.</li></ul><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="./Text.html">Text</a> -- base text component</li></ul>`,15)])])}const m=t(n,[["render",o]]);export{c as __pageData,m as default};
